import { Request, Response, NextFunction } from 'express';
import sharp from 'sharp';
import fs from 'node:fs';

export const uploadPhoto = async (req: Request, res: Response, next: NextFunction) => {
  try {
    if (!req.file) return res.status(400).json({ error: 'NO_FILE' });
    const resized = await sharp(req.file.buffer).resize(1200, 1200, { fit: 'inside' }).webp({ quality: 80 }).toBuffer();
    const thumbBuf = await sharp(req.file.buffer).resize(200, 200, { fit: 'cover' }).webp({ quality: 70 }).toBuffer();
    const id = Date.now();
    fs.writeFileSync(`/var/photos/${id}.webp`, resized);
    fs.writeFileSync(`/var/photos/${id}-thumb.webp`, thumbBuf);
    res.json({ url: `/photos/${id}.webp`, thumb: `/photos/${id}-thumb.webp` });
  } catch (err) { next(err); }
};

import sharp from 'sharp';

export default async function resize({ buffer, width, height, quality, fit }: { buffer: ArrayBuffer; width: number; height: number; quality: number; fit: 'inside' | 'cover' }): Promise<Uint8Array> {
  const out = await sharp(Buffer.from(buffer)).resize(width, height, { fit }).webp({ quality }).toBuffer();
  return new Uint8Array(out);
}

import Piscina from 'piscina';
import path from 'node:path';
import fs from 'node:fs/promises';
import { HttpError } from '../errors/http-error';

const pool = new Piscina({
  filename: path.resolve(__dirname, '../workers/image.worker.js'),
  maxThreads: Math.max(2, Math.floor(require('os').cpus().length - 1)),
  maxQueue: 200
});

export const imageService = {
  async processUpload(buffer: Buffer, baseId: string) {
    if (pool.queueSize > 150) throw new HttpError(503, 'BUSY');
    const [main, thumb] = await Promise.all([
      pool.run({ buffer: buffer.buffer.slice(buffer.byteOffset, buffer.byteOffset + buffer.byteLength), width: 1200, height: 1200, quality: 80, fit: 'inside' }),
      pool.run({ buffer: buffer.buffer.slice(buffer.byteOffset, buffer.byteOffset + buffer.byteLength), width: 200, height: 200, quality: 70, fit: 'cover' })
    ]) as Uint8Array[];
    await Promise.all([
      fs.writeFile(`/var/photos/${baseId}.webp`, main),
      fs.writeFile(`/var/photos/${baseId}-thumb.webp`, thumb)
    ]);
    return { url: `/photos/${baseId}.webp`, thumb: `/photos/${baseId}-thumb.webp` };
  },
  queueDepth: () => pool.queueSize
};

import { Request, Response, NextFunction } from 'express';
import crypto from 'node:crypto';
import { imageService } from '../services/image.service';

export const uploadPhoto = async (req: Request, res: Response, next: NextFunction) => {
  try {
    if (!req.file) return res.status(400).json({ error: 'NO_FILE' });
    const id = `${Date.now()}-${crypto.randomBytes(4).toString('hex')}`;
    const result = await imageService.processUpload(req.file.buffer, id);
    res.json(result);
  } catch (err) {
    if ((err as { status?: number }).status === 503) res.setHeader('Retry-After', '2');
    next(err);
  }
};

import { useState } from 'react';

export function usePhotoUpload() {
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const upload = async (file: File, retries = 3): Promise<{ url: string; thumb: string }> => {
    setUploading(true); setError(null);
    const fd = new FormData(); fd.append('file', file);
    try {
      for (let attempt = 0; attempt <= retries; attempt++) {
        const res = await fetch('/api/photos', { method: 'POST', credentials: 'include', body: fd });
        if (res.ok) return await res.json();
        if (res.status === 503 && attempt < retries) {
          const wait = Number(res.headers.get('Retry-After') ?? '2') * 1000 * Math.pow(2, attempt);
          await new Promise(r => setTimeout(r, wait));
          continue;
        }
        throw new Error(`HTTP ${res.status}`);
      }
      throw new Error('exhausted retries');
    } catch (e) { setError((e as Error).message); throw e; }
    finally { setUploading(false); }
  };

  return { upload, uploading, error };
}

import { useEffect, useState } from 'react';
import { fetchNotifications } from '../../api/notifications';

type Notification = { _id: string; text: string; createdAt: string };

export function NotificationCenter() {
  const [items, setItems] = useState<Notification[]>([]);
  const [readIds, setReadIds] = useState<Set<string>>(() => new Set(JSON.parse(localStorage.getItem('readIds') ?? '[]')));
  useEffect(() => { fetchNotifications().then(setItems); }, []);
  const markRead = (id: string) => {
    const next = new Set(readIds); next.add(id);
    setReadIds(next);
    localStorage.setItem('readIds', JSON.stringify(Array.from(next)));
  };
  return <ul>{items.map(n => <li key={n._id} className={readIds.has(n._id) ? 'opacity-50' : ''} onClick={() => markRead(n._id)}>{n.text}</li>)}</ul>;
}

import { Request, Response, NextFunction } from 'express';
import { NotificationModel } from '../models/notification.model';

export const list = async (req: Request, res: Response, next: NextFunction) => {
  try { res.json({ items: await NotificationModel.find({ userId: req.user!.id }).sort({ createdAt: -1 }).limit(50).lean() }); }
  catch (err) { next(err); }
};

import { Request, Response, NextFunction } from 'express';
import { NotificationModel } from '../models/notification.model';
import { NotificationReadModel } from '../models/notification-read.model';
import { io } from '../infra/socketio';

export const list = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const items = await NotificationModel.find({ userId: req.user!.id }).sort({ createdAt: -1 }).limit(50).lean();
    const reads = await NotificationReadModel.find({ userId: req.user!.id, notificationId: { $in: items.map(i => i._id) } }).lean();
    const readSet = new Set(reads.map(r => r.notificationId.toString()));
    res.json({ items: items.map(i => ({ ...i, read: readSet.has(i._id.toString()) })) });
  } catch (err) { next(err); }
};

export const markRead = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const userId = req.user!.id;
    const { id } = req.params;
    const result = await NotificationReadModel.updateOne({ userId, notificationId: id }, { $setOnInsert: { readAt: new Date() } }, { upsert: true });
    if (result.upsertedCount > 0) {
      io.of('/notifications').to(`user:${userId}`).emit('notification:read', { id, readAt: new Date() });
    }
    res.json({ ok: true });
  } catch (err) { next(err); }
};

export const readsSince = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const since = new Date(req.query.since as string);
    const reads = await NotificationReadModel.find({ userId: req.user!.id, readAt: { $gt: since } }).lean();
    res.json({ reads });
  } catch (err) { next(err); }
};

import { Server, Socket } from 'socket.io';

interface AuthedSocket extends Socket { data: { userId: string } }

export function attachNotificationNamespace(io: Server) {
  const ns = io.of('/notifications');
  ns.on('connection', (socket: AuthedSocket) => {
    socket.join(`user:${socket.data.userId}`);
  });
}

import { useEffect, useRef, useState } from 'react';
import { io, Socket } from 'socket.io-client';
import { fetchNotifications, postReadsSince, markReadApi } from '../../api/notifications';

export type Notification = { _id: string; text: string; createdAt: string; read: boolean };

export function useNotifications(token: string) {
  const [items, setItems] = useState<Notification[]>([]);
  const lastSync = useRef<string>(new Date().toISOString());
  const socketRef = useRef<Socket | null>(null);

  useEffect(() => {
    fetchNotifications().then(r => { setItems(r.items); lastSync.current = new Date().toISOString(); });
    const socket = io('/notifications', { auth: { token }, transports: ['websocket'] });
    socketRef.current = socket;
    socket.on('connect', async () => {
      const r = await postReadsSince(lastSync.current);
      if (r.reads.length) {
        setItems(prev => prev.map(it => r.reads.find((x: { notificationId: string }) => x.notificationId === it._id) ? { ...it, read: true } : it));
      }
      lastSync.current = new Date().toISOString();
    });
    socket.on('notification:read', ({ id }: { id: string }) => {
      setItems(prev => prev.map(it => it._id === id ? { ...it, read: true } : it));
    });
    return () => { socket.removeAllListeners(); socket.disconnect(); };
  }, [token]);

  const markRead = async (id: string) => {
    setItems(prev => prev.map(it => it._id === id ? { ...it, read: true } : it));
    try { await markReadApi(id); } catch { /* server is source of truth; broadcast will reconcile */ }
  };
  return { items, markRead };
}

import { useNotifications } from './useNotifications';

export function NotificationCenter({ token }: { token: string }) {
  const { items, markRead } = useNotifications(token);
  return (
    <ul className="divide-y">
      {items.map(n => (
        <li key={n._id} className={`p-3 cursor-pointer ${n.read ? 'opacity-50' : 'font-medium'}`} onClick={() => !n.read && markRead(n._id)}>
          {n.text}
        </li>
      ))}
    </ul>
  );
}

import { Request, Response, NextFunction } from 'express';
import { OrderModel } from '../models/order.model';

export const cancelOrder = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const order = await OrderModel.findById(req.params.id);
    if (!order) return res.status(404).json({ error: 'not found' });
    if (order.status === 'shipped') return res.status(400).json({ message: 'too late' });
    if (order.userId.toString() !== req.user!.id) return res.status(403).json({ err: 'forbidden' });
    order.status = 'cancelled';
    await order.save();
    res.json({ order });
  } catch (err) { next(err); }
};

import { Request, Response, NextFunction } from 'express';

export const errorMiddleware = (err: any, _req: Request, res: Response, _next: NextFunction) => {
  console.error(err);
  res.status(500).json({ error: err.message || 'internal' });
};

export type Severity = 'info' | 'warn' | 'error' | 'fatal';

export class AppError extends Error {
  constructor(
    public readonly code: string,
    message: string,
    public readonly status: number,
    public readonly severity: Severity = 'warn',
    public readonly details?: unknown
  ) {
    super(message);
    this.name = new.target.name;
  }
}

export class NotFoundError extends AppError {
  constructor(resource: string, id?: string) { super('NOT_FOUND', `${resource}${id ? ` ${id}` : ''} not found`, 404, 'info'); }
}

export class ForbiddenError extends AppError {
  constructor(reason = 'Forbidden') { super('FORBIDDEN', reason, 403, 'warn'); }
}

export class ConflictError extends AppError {
  constructor(code: string, message: string, details?: unknown) { super(code, message, 409, 'warn', details); }
}

export class ValidationError extends AppError {
  constructor(details: unknown) { super('VALIDATION_FAILED', 'Validation failed', 400, 'info', details); }
}

export class InternalError extends AppError {
  constructor(message: string, details?: unknown) { super('INTERNAL', message, 500, 'error', details); }
}

import { Request, Response, NextFunction } from 'express';
import { AppError, InternalError } from '../errors/app-error';
import { logger } from '../infra/logger';

export const errorMiddleware = (err: unknown, req: Request, res: Response, _next: NextFunction) => {
  const requestId = (req.headers['x-request-id'] as string) ?? 'no-request-id';
  const appErr = err instanceof AppError ? err : new InternalError((err as Error)?.message ?? 'Unknown error');
  logger[appErr.severity]({ requestId, code: appErr.code, status: appErr.status, path: req.path, method: req.method, details: appErr.details, stack: process.env.NODE_ENV === 'production' ? undefined : (err as Error)?.stack }, appErr.message);
  const body: { error: { code: string; message: string; requestId: string; details?: unknown } } = {
    error: { code: appErr.code, message: appErr.status >= 500 ? 'Internal server error' : appErr.message, requestId }
  };
  if (appErr.details && appErr.status < 500) body.error.details = appErr.details;
  res.status(appErr.status).json(body);
};

import { Request, Response, NextFunction } from 'express';
import { OrderModel } from '../models/order.model';
import { NotFoundError, ForbiddenError, ConflictError } from '../errors/app-error';

export const cancelOrder = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const order = await OrderModel.findById(req.params.id);
    if (!order) throw new NotFoundError('Order', req.params.id);
    if (order.userId.toString() !== req.user!.id) throw new ForbiddenError('Not the order owner');
    if (order.status === 'shipped') throw new ConflictError('ORDER_ALREADY_SHIPPED', 'Cannot cancel a shipped order');
    order.status = 'cancelled';
    await order.save();
    res.json({ order });
  } catch (err) { next(err); }
};

export type ApiErrorBody = { error: { code: string; message: string; requestId: string; details?: unknown } };

export class ApiError extends Error {
  constructor(public readonly code: string, message: string, public readonly status: number, public readonly requestId: string, public readonly details?: unknown) {
    super(message);
  }
}

export async function parseErrorResponse(res: Response): Promise<ApiError> {
  let body: ApiErrorBody | null = null;
  try { body = await res.json() as ApiErrorBody; } catch { /* ignore */ }
  const err = body?.error;
  return new ApiError(err?.code ?? 'UNKNOWN', err?.message ?? `HTTP ${res.status}`, res.status, err?.requestId ?? '', err?.details);
}

export function isApiErrorCode(err: unknown, code: string): boolean {
  return err instanceof ApiError && err.code === code;
}

import { useState } from 'react';
import { cancelOrder } from '../../api/orders';
import { isApiErrorCode } from '../../lib/api-error';

export function CancelButton({ orderId }: { orderId: string }) {
  const [error, setError] = useState<string | null>(null);
  const onClick = async () => {
    try { await cancelOrder(orderId); }
    catch (err) {
      if (isApiErrorCode(err, 'ORDER_ALREADY_SHIPPED')) setError('This order has already shipped and cannot be cancelled.');
      else if (isApiErrorCode(err, 'FORBIDDEN')) setError('You do not own this order.');
      else setError('Something went wrong.');
    }
  };
  return (<><button onClick={onClick} className="px-3 py-1 bg-red-600 text-white rounded">Cancel</button>{error && <div className="text-red-600 text-sm">{error}</div>}</>);
}

