import { Request, Response, NextFunction } from 'express';
import { CommentModel } from '../models/comment.model';
import { ValidationError } from '../errors/app-error';

const MAX_LENGTH = 10000;
const FORBIDDEN_PATTERNS = [/<script\b/i, /javascript:/i, /on\w+\s*=/i];

export const create = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const md = (req.body.markdown as string) ?? '';
    if (md.length > MAX_LENGTH) throw new ValidationError({ field: 'markdown', reason: 'TOO_LONG' });
    for (const p of FORBIDDEN_PATTERNS) if (p.test(md)) throw new ValidationError({ field: 'markdown', reason: 'FORBIDDEN_CONTENT' });
    const c = await CommentModel.create({ userId: req.user!.id, postId: req.body.postId, markdown: md });
    res.status(201).json({ comment: c });
  } catch (err) { next(err); }
};

import { marked } from 'marked';
import DOMPurify from 'dompurify';
import { useMemo } from 'react';

const ALLOWED_IMG_HOSTS = new Set(['cdn.example.com', 'images.example.com']);

DOMPurify.addHook('afterSanitizeAttributes', (node) => {
  if (node.tagName === 'A') {
    node.setAttribute('target', '_blank');
    node.setAttribute('rel', 'noopener noreferrer');
  }
  if (node.tagName === 'IMG') {
    const src = node.getAttribute('src') ?? '';
    try {
      const url = new URL(src, window.location.origin);
      if (!ALLOWED_IMG_HOSTS.has(url.host)) node.removeAttribute('src');
    } catch { node.removeAttribute('src'); }
  }
});

export function CommentBody({ markdown }: { markdown: string }) {
  const safeHtml = useMemo(() => {
    const html = marked.parse(markdown, { breaks: true }) as string;
    return DOMPurify.sanitize(html, {
      ALLOWED_TAGS: ['p','br','strong','em','u','s','a','code','pre','blockquote','ul','ol','li','h1','h2','h3','h4','img','hr','table','thead','tbody','tr','th','td','details','summary'],
      ALLOWED_ATTR: ['href','title','src','alt','class','target','rel']
    });
  }, [markdown]);
  return <div className="prose" dangerouslySetInnerHTML={{ __html: safeHtml }} />;
}

