import { z } from 'zod';

export const filterSchema = z.object({
  from: z.string().regex(/^\d{4}-\d{2}-\d{2}$/).default('2026-01-01'),
  to: z.string().regex(/^\d{4}-\d{2}-\d{2}$/).default('2026-12-31'),
  country: z.string().nullable().default(null),
  segment: z.enum(['all','paid','free']).default('all'),
  groupBy: z.enum(['day','week','month']).default('day')
});

export type Filters = z.infer<typeof filterSchema>;

import { useSearchParams } from 'react-router-dom';
import { useCallback, useMemo } from 'react';
import { filterSchema, type Filters } from './filterSchema';

export function useFilters() {
  const [searchParams, setSearchParams] = useSearchParams();

  const filters = useMemo<Filters>(() => {
    const raw: Record<string, string | null> = {};
    for (const k of Object.keys(filterSchema.shape)) {
      const v = searchParams.get(k);
      if (v !== null) raw[k] = v;
    }
    const parsed = filterSchema.safeParse(raw);
    return parsed.success ? parsed.data : filterSchema.parse({});
  }, [searchParams]);

  const setFilter = useCallback(<K extends keyof Filters>(key: K, value: Filters[K]) => {
    const next = new URLSearchParams(searchParams);
    if (value === null || value === filterSchema.shape[key].safeParse(undefined).data) next.delete(key);
    else next.set(key, String(value));
    setSearchParams(next, { replace: true });
  }, [searchParams, setSearchParams]);

  const setMany = useCallback((patch: Partial<Filters>) => {
    const next = new URLSearchParams(searchParams);
    for (const [k, v] of Object.entries(patch)) {
      if (v === null || v === undefined) next.delete(k);
      else next.set(k, String(v));
    }
    setSearchParams(next, { replace: true });
  }, [searchParams, setSearchParams]);

  const reset = useCallback(() => setSearchParams(new URLSearchParams(), { replace: false }), [setSearchParams]);

  return { filters, setFilter, setMany, reset };
}

import { useFilters } from './useFilters';
import { useAnalytics } from './useAnalytics';

export function Dashboard() {
  const { filters, setFilter, reset } = useFilters();
  const data = useAnalytics(filters);
  return (
    <div>
      <input type="date" value={filters.from} onChange={e => setFilter('from', e.target.value)} />
      <input type="date" value={filters.to} onChange={e => setFilter('to', e.target.value)} />
      <select value={filters.segment} onChange={e => setFilter('segment', e.target.value as 'all'|'paid'|'free')}>
        <option>all</option><option>paid</option><option>free</option>
      </select>
      <select value={filters.groupBy} onChange={e => setFilter('groupBy', e.target.value as 'day'|'week'|'month')}>
        <option>day</option><option>week</option><option>month</option>
      </select>
      <button onClick={reset} className="px-3 py-1 border rounded">Reset</button>
      <ShareLink filters={filters} />
      {data && <Chart data={data} />}
    </div>
  );
}

