import { Canvas, useThree } from '@react-three/fiber';
import { Suspense, useEffect, useRef } from 'react';
import * as THREE from 'three';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);

const KEYFRAMES: { pos: [number,number,number]; look: [number,number,number] }[] = [
  { pos: [0, 2, 8], look: [0,0,0] },
  { pos: [4, 1, 4], look: [0,0,0] },
  { pos: [-3, 3, 3], look: [0,1,0] },
  { pos: [0, 5, 10], look: [0,0,0] }
];

function CameraRig({ progress }: { progress: { value: number } }) {
  const { camera } = useThree();
  const curve = useRef(new THREE.CatmullRomCurve3(KEYFRAMES.map(k => new THREE.Vector3(...k.pos))));
  useEffect(() => {
    let raf = 0;
    const tick = () => {
      const p = curve.current.getPoint(progress.value);
      camera.position.copy(p);
      const k = Math.min(KEYFRAMES.length - 1, Math.floor(progress.value * (KEYFRAMES.length - 1)));
      const look = KEYFRAMES[k].look;
      camera.lookAt(look[0], look[1], look[2]);
      raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [camera, progress]);
  return null;
}

function Scene() {
  return (
    <>
      <ambientLight intensity={0.4} />
      <directionalLight position={[5, 10, 7]} intensity={0.8} />
      <mesh position={[0, 0, 0]}>
        <torusKnotGeometry args={[1, 0.3, 128, 16]} />
        <meshStandardMaterial color="#5b8def" />
      </mesh>
    </>
  );
}

export function Hero3D() {
  const progressRef = useRef({ value: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const reduced = typeof window !== 'undefined' && window.matchMedia('(prefers-reduced-motion: reduce)').matches;

  useEffect(() => {
    if (reduced) { progressRef.current.value = 1; return; }
    const trigger = ScrollTrigger.create({
      trigger: containerRef.current!,
      start: 'top top',
      end: '+=3000',
      scrub: 0.5,
      pin: true,
      onUpdate: self => { progressRef.current.value = self.progress; }
    });
    return () => { trigger.kill(); };
  }, [reduced]);

  return (
    <div ref={containerRef} className="h-screen relative">
      <Canvas dpr={[1, 2]} camera={{ position: [0, 2, 8], fov: 50 }} onCreated={({ gl, scene }) => { (gl as any).__scene = scene; }}>
