import { Request, Response, NextFunction } from 'express';
import { redis } from '../infra/redis';
import { OrgModel } from '../models/org.model';
import { HttpError } from '../errors/http-error';

type Category = 'read' | 'write' | 'export';
const TIER_LIMITS: Record<string, Record<Category, number>> = {
  free: { read: 1000, write: 100, export: 5 },
  pro: { read: 50_000, write: 10_000, export: 100 },
  enterprise: { read: Infinity, write: Infinity, export: Infinity }
};

function tenantDate(tz: string): string {
  return new Intl.DateTimeFormat('en-CA', { timeZone: tz, year: 'numeric', month: '2-digit', day: '2-digit' }).format(new Date());
}

export function quota(category: Category) {
  return async (req: Request, res: Response, next: NextFunction) => {
    try {
      const orgId = req.apiKey?.orgId ?? (req as any).orgId;
      if (!orgId) return next();
      const org = await OrgModel.findById(orgId).lean();
      if (!org) throw new HttpError(404, 'ORG_NOT_FOUND');
      const tier = (org.tier as keyof typeof TIER_LIMITS) ?? 'free';
      const limit = TIER_LIMITS[tier][category];
      if (!Number.isFinite(limit)) return next();
      const date = tenantDate(org.timezone ?? 'UTC');
      const key = `quota:${orgId}:${category}:${date}`;
      const count = await redis.incr(key);
      if (count === 1) await redis.expire(key, 60 * 60 * 30);
      const remaining = Math.max(0, limit - count);
      res.setHeader('X-RateLimit-Limit', String(limit));
      res.setHeader('X-RateLimit-Remaining', String(remaining));
      res.setHeader('X-RateLimit-Reset', date + 'T00:00:00');
      if (count > limit) return next(new HttpError(429, `QUOTA_EXCEEDED:${category}`));
      next();
    } catch (err) { next(err); }
  };
}

