type Pending = { id: string; resolve: (p: unknown) => void; reject: (e: Error) => void };

const pending: Pending[] = [];
const cache = new Map<string, unknown>();
const CACHE_LIMIT = 500;
let scheduled = false;

async function flush() {
  scheduled = false;
  const batch = pending.splice(0);
  if (batch.length === 0) return;
  const ids = Array.from(new Set(batch.map(b => b.id)));
  try {
    const res = await fetch('/api/products/batch', { method: 'POST', credentials: 'include', headers: { 'content-type': 'application/json' }, body: JSON.stringify({ ids }) });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json() as { products: (unknown | null)[] };
    const byId = new Map<string, unknown>();
    ids.forEach((id, i) => { const p = data.products[i]; if (p) { byId.set(id, p); cache.set(id, p); } });
    if (cache.size > CACHE_LIMIT) { for (const k of Array.from(cache.keys()).slice(0, cache.size - CACHE_LIMIT)) cache.delete(k); }
    for (const p of batch) { const product = byId.get(p.id); if (product) p.resolve(product); else p.reject(new Error('NOT_FOUND')); }
  } catch (err) { for (const p of batch) p.reject(err as Error); }
}

export function loadProduct<T>(id: string): Promise<T> {
  const cached = cache.get(id);
  if (cached) return Promise.resolve(cached as T);
  return new Promise((resolve, reject) => {
    pending.push({ id, resolve: resolve as (p: unknown) => void, reject });
    if (!scheduled) { scheduled = true; queueMicrotask(flush); }
  });
}

export function invalidateProduct(id: string) { cache.delete(id); }

