import crypto from 'node:crypto';
import { kms } from '../infra/kms';

export type Encrypted = { ct: string; iv: string; tag: string; encDek: string; kekVersion: number };

export async function encryptField(plaintext: string): Promise<Encrypted> {
  const dek = crypto.randomBytes(32);
  const iv = crypto.randomBytes(12);
  const cipher = crypto.createCipheriv('aes-256-gcm', dek, iv);
  const ct = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()]);
  const tag = cipher.getAuthTag();
  const { encrypted, version } = await kms.encrypt(dek);
  return { ct: ct.toString('base64'), iv: iv.toString('base64'), tag: tag.toString('base64'), encDek: encrypted, kekVersion: version };
}

export async function decryptField(env: Encrypted): Promise<string> {
  const dek = await kms.decrypt(env.encDek, env.kekVersion);
  const decipher = crypto.createDecipheriv('aes-256-gcm', dek, Buffer.from(env.iv, 'base64'));
  decipher.setAuthTag(Buffer.from(env.tag, 'base64'));
  return Buffer.concat([decipher.update(Buffer.from(env.ct, 'base64')), decipher.final()]).toString('utf8');
}

export function blindIndex(plaintext: string, secret: Buffer): string {
  return crypto.createHmac('sha256', secret).update(plaintext.normalize('NFKC')).digest('base64url');
}

