import { CustomerModel } from '../models/customer.model';
import { encryptField, decryptField, blindIndex } from '../crypto/envelope';
import { auditLog } from './audit.service';

const INDEX_SECRET = Buffer.from(process.env.PII_INDEX_SECRET!, 'base64');

export const customerService = {
  async create(input: { email: string; nationalId: string; dob: string }) {
    const [nidCipher, dobCipher] = await Promise.all([encryptField(input.nationalId), encryptField(input.dob)]);
    return CustomerModel.create({ email: input.email, nationalIdCipher: nidCipher, nationalIdIndex: blindIndex(input.nationalId, INDEX_SECRET), dobCipher });
  },
  async findByNationalId(nationalId: string, actorId: string) {
    const idx = blindIndex(nationalId, INDEX_SECRET);
    const doc = await CustomerModel.findOne({ nationalIdIndex: idx });
    if (!doc) return null;
    const plain = await decryptField(doc.nationalIdCipher);
    if (plain !== nationalId) return null;
    auditLog({ actorId, action: 'pii.decrypt', target: doc._id.toString(), field: 'nationalId' }).catch(() => {});
    return doc;
  },
  async getPlainDob(customerId: string, actorId: string) {
    const doc = await CustomerModel.findById(customerId);
    if (!doc) return null;
    const dob = await decryptField(doc.dobCipher);
    auditLog({ actorId, action: 'pii.decrypt', target: customerId, field: 'dob' }).catch(() => {});
    return dob;
  }
};

import { CustomerModel } from '../models/customer.model';
import { kms } from '../infra/kms';

export async function rotateKeks() {
  const currentVersion = await kms.currentVersion();
  const cursor = CustomerModel.find({ 'nationalIdCipher.kekVersion': { $lt: currentVersion } }).cursor();
  for await (const doc of cursor) {
    const dek = await kms.decrypt(doc.nationalIdCipher.encDek, doc.nationalIdCipher.kekVersion);
    const { encrypted, version } = await kms.encrypt(dek);
    doc.nationalIdCipher.encDek = encrypted;
    doc.nationalIdCipher.kekVersion = version;
    await doc.save();
  }
}

