export type Mutation<TState> = {
  id: string;
  type: string;
  apply: (state: TState) => TState;
  rollback: (state: TState) => TState;
  commit: () => Promise<void>;
};

export type QueueState<TState> = { state: TState; pending: Mutation<TState>[] };

export class MutationQueue<TState> {
  private listeners = new Set<() => void>();
  private processing = false;
  constructor(private current: TState, private persist?: (pending: Mutation<TState>[]) => void) {}
  getState(): TState { return this.current; }
  subscribe(l: () => void) { this.listeners.add(l); return () => this.listeners.delete(l); }
  private emit() { for (const l of this.listeners) l(); }
  private pending: Mutation<TState>[] = [];

  enqueue(m: Mutation<TState>) {
    this.current = m.apply(this.current);
    this.pending.push(m);
    this.persist?.(this.pending);
    this.emit();
    void this.drain();
  }

  private async drain() {
    if (this.processing) return;
    this.processing = true;
    try {
      while (this.pending.length) {
        const head = this.pending[0];
        try {
          await head.commit();
          this.pending.shift();
          this.persist?.(this.pending);
          this.emit();
        } catch (err) {
          const toRollback = this.pending.splice(0);
          for (let i = toRollback.length - 1; i >= 0; i--) this.current = toRollback[i].rollback(this.current);
          this.persist?.(this.pending);
          this.emit();
          throw err;
        }
      }
    } finally { this.processing = false; }
  }

  retry() { void this.drain(); }
}

