const KEY = 'lb:global';

export const leaderboardService = {
  async addScore(userId: string, score: number) {
    await redis.zAdd(KEY, [{ score, value: userId }]);
  },
  async top(n: number) {
    const entries = await redis.zRangeWithScores(KEY, 0, n - 1, { REV: true });
    return entries.map((e, i) => ({ rank: i + 1, userId: e.value, score: e.score }));
  },
  async rankOf(userId: string) {
