};

import { Server, Socket } from 'socket.io';
import { leaderboardService } from '../services/leaderboard.service';
import { messageBus } from '../events/message.bus';

type Delta = { type: 'score:change'; userId: string; newRank: number; newScore: number; oldRank: number | null };
let version = 0;
const recent: Delta[] = [];

export function attachLeaderboardNamespace(io: Server) {
  const ns = io.of('/leaderboard');
  ns.on('connection', async (socket: Socket) => {
    const userId = (socket as Socket & { data: { userId: string } }).data.userId;
    socket.on('lb:join', async (since?: number) => {
      if (since && version - since < 200 && recent.length) {
        const slice = recent.slice(-(version - since));
        socket.emit('lb:deltas', { version, deltas: slice });
      } else {
        const top = await leaderboardService.top(100);
        const me = await leaderboardService.rankOf(userId);
        socket.emit('lb:snapshot', { version, top, me });
      }
    });
  });

  messageBus.on('score.change' as never, async (evt: { userId: string; newScore: number; oldRank: number | null }) => {
    const rank = await leaderboardService.rankOf(evt.userId);
    if (!rank) return;
    version += 1;
    const delta: Delta = { type: 'score:change', userId: evt.userId, newRank: rank.rank, newScore: evt.newScore, oldRank: evt.oldRank };
    recent.push(delta);
    if (recent.length > 500) recent.shift();
    ns.emit('lb:deltas', { version, deltas: [delta] });
  });
}

import { useEffect, useRef, useState } from 'react';
import { io } from 'socket.io-client';

type Entry = { rank: number; userId: string; score: number };
type Snapshot = { version: number; top: Entry[]; me: { rank: number; score: number } | null };
type Delta = { type: 'score:change'; userId: string; newRank: number; newScore: number };

export function useLeaderboard(token: string) {
  const [top, setTop] = useState<Entry[]>([]);
  const [me, setMe] = useState<{ rank: number; score: number } | null>(null);
  const versionRef = useRef(0);

  useEffect(() => {
    const socket = io('/leaderboard', { auth: { token }, transports: ['websocket'] });
    socket.on('connect', () => socket.emit('lb:join', versionRef.current || undefined));
    socket.on('lb:snapshot', (s: Snapshot) => { setTop(s.top); setMe(s.me); versionRef.current = s.version; });
    socket.on('lb:deltas', (msg: { version: number; deltas: Delta[] }) => {
      versionRef.current = msg.version;
      setTop(prev => {
        const map = new Map(prev.map(e => [e.userId, e] as const));
        for (const d of msg.deltas) {
          if (d.newRank <= 100) map.set(d.userId, { rank: d.newRank, userId: d.userId, score: d.newScore });
        }
        return Array.from(map.values()).sort((a, b) => a.rank - b.rank).slice(0, 100);
      });
    });
    return () => { socket.removeAllListeners(); socket.disconnect(); };
  }, [token]);

  return { top, me };
}

