  const reportW = createReportWorker(async (p) => { await generateReport(p as any); });
  emailW.on('failed', (job, err) => console.error('email failed', job?.id, err));
  reportW.on('failed', (job, err) => console.error('report failed', job?.id, err));
  process.on('SIGTERM', async () => { await Promise.all([emailW.close(), reportW.close()]); process.exit(0); });
}
main();

