import { Schema } from 'mongoose';
import { AuditLogModel } from '../models/audit-log.model';
import { tryGetContext } from '../context/context';

export function auditPlugin(schema: Schema, opts: { entity: string; redact?: string[] }) {
  const redact = new Set(opts.redact ?? []);
  function snap(doc: any): Record<string, unknown> {
    const out: Record<string, unknown> = {};
    for (const [k, v] of Object.entries(doc.toObject ? doc.toObject() : doc)) {
      if (k === '__v') continue;
      out[k] = redact.has(k) ? '[REDACTED]' : v;
    }
    return out;
  }
  function diff(before: Record<string, unknown>, after: Record<string, unknown>) {
    const changes: Record<string, { before: unknown; after: unknown }> = {};
    const keys = new Set([...Object.keys(before), ...Object.keys(after)]);
    for (const k of keys) if (JSON.stringify(before[k]) !== JSON.stringify(after[k])) changes[k] = { before: before[k], after: after[k] };
    return changes;
  }
  schema.pre('save', async function(next) {
    (this as any).__auditBefore = this.isNew ? {} : snap(await this.$model().findById(this._id).lean());
    next();
  });
  schema.post('save', async function(doc) {
    const before = (this as any).__auditBefore;
    const after = snap(doc);
    const changes = diff(before, after);
    if (Object.keys(changes).length === 0) return;
    const ctx = tryGetContext();
    await AuditLogModel.create({ entity: opts.entity, entityId: doc._id, action: before && Object.keys(before).length ? 'update' : 'create', changes, actorId: ctx?.user?.id ?? 'system', requestId: ctx?.requestId, at: new Date() });
  });
}

