type TenantDbConfig = { tier: 'shared' | 'dedicated'; mongoUrl: string };

const connectionPool = new Map<string, Connection>();
const MAX_DEDICATED_CONNECTIONS = 50;

function registerModels(conn: Connection) {
  if (!conn.models.Order) conn.model('Order', new Schema(OrderSchemaDef, { timestamps: true }));
  return { OrderModel: conn.model('Order') };
}

let shared: Connection | null = null;

export async function getDbForTenant(config: TenantDbConfig) {
  if (config.tier === 'shared') {
    if (!shared) { shared = mongoose.createConnection(config.mongoUrl); await shared.asPromise(); }
    return registerModels(shared);
  }
  let conn = connectionPool.get(config.mongoUrl);
  if (!conn) {
    if (connectionPool.size >= MAX_DEDICATED_CONNECTIONS) {
      const evictKey = connectionPool.keys().next().value;
      const evict = connectionPool.get(evictKey!);
      await evict?.close();
      connectionPool.delete(evictKey!);
    }
    conn = mongoose.createConnection(config.mongoUrl, { maxPoolSize: 10 });
    await conn.asPromise();
    connectionPool.set(config.mongoUrl, conn);
  }
  return registerModels(conn);
}

