import { useRef } from 'react';
export function useRenderLogger(name: string, props: Record<string, unknown>) {
  const prev = useRef<Record<string, unknown> | null>(null);
  if (process.env.NODE_ENV === 'development') {
    if (prev.current) {
      const changed: string[] = [];
      for (const k of Object.keys(props)) if (!Object.is(props[k], prev.current[k])) changed.push(k);
      if (changed.length) console.log(`[render] ${name} props changed: ${changed.join(', ')}`);
    }
    prev.current = { ...props };
  }
}

