type Listener<T> = (msg: T) => void;

type Channels = {
  auth: { type: 'logout' };
  notes: { type: 'updated'; id: string; body: string; updatedAt: string };
};

function createChannel<K extends keyof Channels>(name: K) {
  const listeners = new Set<Listener<Channels[K]>>();
  let bc: BroadcastChannel | null = null;
  try { bc = new BroadcastChannel(`app:${name}`); bc.onmessage = (e) => { for (const l of listeners) l(e.data); }; } catch { /* fallback below */ }
  if (!bc) {
    window.addEventListener('storage', (e) => {
      if (e.key !== `bc:${name}` || !e.newValue) return;
      try { const data = JSON.parse(e.newValue) as Channels[K]; for (const l of listeners) l(data); } catch {}
    });
  }
  return {
    post(msg: Channels[K]) {
      if (bc) bc.postMessage(msg);
      else { try { localStorage.setItem(`bc:${name}`, JSON.stringify({ ...msg, _ts: Date.now() })); } catch {} }
    },
    subscribe(l: Listener<Channels[K]>) { listeners.add(l); return () => listeners.delete(l); }
  };
}

