import jwt from 'jsonwebtoken';
import crypto from 'node:crypto';
import { RefreshTokenModel } from '../models/refresh-token.model';
import { HttpError } from '../errors/http-error';

const ISSUER = process.env.JWT_ISSUER!;
const AUDIENCE = process.env.JWT_AUDIENCE!;

export async function issueTokenPair(userId: string, familyId: string = crypto.randomUUID()) {
  const accessJti = crypto.randomUUID();
  const refreshJti = crypto.randomUUID();
  const access = jwt.sign({ sub: userId, jti: accessJti }, process.env.JWT_ACCESS_SECRET!, { expiresIn: '15m', issuer: ISSUER, audience: AUDIENCE });
  const refresh = jwt.sign({ sub: userId, jti: refreshJti, family: familyId }, process.env.JWT_REFRESH_SECRET!, { expiresIn: '30d', issuer: ISSUER, audience: AUDIENCE });
  await RefreshTokenModel.create({ jti: refreshJti, family: familyId, userId, status: 'active', expiresAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000) });
  return { access, refresh, accessJti, refreshJti, familyId };
}

export function verifyAccess(token: string) {
  const payload = jwt.verify(token, process.env.JWT_ACCESS_SECRET!, { issuer: ISSUER, audience: AUDIENCE }) as { sub: string; jti: string };
  return payload;
}

export async function rotateRefresh(presented: string) {
  let payload: { sub: string; jti: string; family: string };
  try { payload = jwt.verify(presented, process.env.JWT_REFRESH_SECRET!, { issuer: ISSUER, audience: AUDIENCE }) as any; }
  catch { throw new HttpError(401, 'INVALID_REFRESH'); }
  const record = await RefreshTokenModel.findOne({ jti: payload.jti });
  if (!record) {
    await RefreshTokenModel.updateMany({ family: payload.family }, { $set: { status: 'revoked' } });
    throw new HttpError(401, 'REFRESH_REUSE_DETECTED');
  }
  if (record.status !== 'active') {
    await RefreshTokenModel.updateMany({ family: payload.family }, { $set: { status: 'revoked' } });
    throw new HttpError(401, 'REFRESH_REUSE_DETECTED');
  }
  record.status = 'rotated';
  await record.save();
  return issueTokenPair(payload.sub, payload.family);
}

import { Request, Response, NextFunction } from 'express';
