export const refresh = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const presented = req.cookies?.rt;
    if (!presented) throw new HttpError(401, 'NO_REFRESH');
    const pair = await rotateRefresh(presented);
    res.cookie('rt', pair.refresh, { httpOnly: true, sameSite: 'lax', secure: true, path: '/api/auth/refresh' });
    res.json({ token: pair.access });
  } catch (err) { next(err); }
};

import { Request, Response, NextFunction } from 'express';
import { verifyAccess } from '../auth/jwt';
import { RevocationModel } from '../models/revocation.model';
import { HttpError } from '../errors/http-error';

export async function requireAuth(req: Request, _res: Response, next: NextFunction) {
  try {
    const auth = req.headers.authorization;
    if (!auth?.startsWith('Bearer ')) throw new HttpError(401, 'UNAUTHENTICATED');
    const payload = verifyAccess(auth.slice(7));
    const revoked = await RevocationModel.findOne({ jti: payload.jti }).lean();
    if (revoked) throw new HttpError(401, 'TOKEN_REVOKED');
    req.user = { id: payload.sub, role: 'user' };
    next();
  } catch (err) { next(new HttpError(401, 'UNAUTHENTICATED')); }
}

let accessToken: string | null = null;
let refreshPromise: Promise<string> | null = null;

async function refreshAccess(): Promise<string> {
  if (!refreshPromise) refreshPromise = (async () => {
    const res = await fetch('/api/auth/refresh', { method: 'POST', credentials: 'include' });
    if (!res.ok) throw new Error('refresh failed');
    const data = await res.json();
    accessToken = data.token;
    return data.token as string;
  })().finally(() => { refreshPromise = null; });
  return refreshPromise;
}

export async function apiFetch(path: string, init: RequestInit = {}): Promise<Response> {
  if (!accessToken) await refreshAccess();
  let res = await fetch(`/api${path}`, { ...init, headers: { ...(init.headers ?? {}), authorization: `Bearer ${accessToken}` } });
  if (res.status === 401) {
    await refreshAccess();
    res = await fetch(`/api${path}`, { ...init, headers: { ...(init.headers ?? {}), authorization: `Bearer ${accessToken}` } });
  }
  return res;
}

