import { useEffect, useRef, useState } from 'react';
import ThreeGlobe from 'three-globe';
import * as THREE from 'three';
import { io } from 'socket.io-client';
import countries from './countries.geo.json';

type Metric = Record<string, number>;

export function Globe3D({ token }: { token: string }) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [metrics, setMetrics] = useState<Metric>({});
  const [hovered, setHovered] = useState<{ name: string; users: number; x: number; y: number } | null>(null);

  useEffect(() => {
    if (!containerRef.current) return;
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    const w = containerRef.current.clientWidth;
    const h = containerRef.current.clientHeight;
    renderer.setSize(w, h);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    containerRef.current.appendChild(renderer.domElement);
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x0b1220);
    const camera = new THREE.PerspectiveCamera(50, w / h, 0.1, 1000);
    camera.position.z = 300;
    scene.add(new THREE.AmbientLight(0xffffff, 0.6));
    const globe = new ThreeGlobe()
      .polygonsData(countries.features)
      .polygonAltitude(0.005)
      .polygonCapColor((f: any) => { const code = f.properties.iso_a2; const n = metrics[code] ?? 0; const t = Math.min(1, n / 1000); return `hsl(${200 - t*200} 70% ${30 + t*30}%)`; })
      .polygonSideColor(() => 'rgba(0,0,0,0.15)');
    scene.add(globe);

    const raycaster = new THREE.Raycaster();
    const mouse = new THREE.Vector2();
    const onMove = (e: MouseEvent) => {
      const rect = renderer.domElement.getBoundingClientRect();
      mouse.x = ((e.clientX - rect.left) / rect.width) * 2 - 1;
      mouse.y = -((e.clientY - rect.top) / rect.height) * 2 + 1;
      raycaster.setFromCamera(mouse, camera);
      const intersects = raycaster.intersectObjects(globe.children, true);
      const hit = intersects.find(i => (i.object as any).__data);
      if (hit) {
        const f = (hit.object as any).__data;
        setHovered({ name: f.properties.name, users: metrics[f.properties.iso_a2] ?? 0, x: e.clientX, y: e.clientY });
      } else setHovered(null);
    };
    renderer.domElement.addEventListener('mousemove', onMove);

    let raf = 0;
    const tick = () => { globe.rotation.y += 0.0005; renderer.render(scene, camera); raf = requestAnimationFrame(tick); };
    raf = requestAnimationFrame(tick);

    return () => {
      cancelAnimationFrame(raf);
      renderer.domElement.removeEventListener('mousemove', onMove);
      scene.traverse(obj => { (obj as any).geometry?.dispose?.(); (obj as any).material?.dispose?.(); });
      renderer.dispose();
      containerRef.current?.removeChild(renderer.domElement);
    };
  }, [metrics]);

  useEffect(() => {
    const socket = io('/geo', { auth: { token }, transports: ['websocket'] });
    socket.on('geo:update', (m: Metric) => setMetrics(m));
    return () => { socket.disconnect(); };
  }, [token]);

  return (
    <div ref={containerRef} className="w-full h-screen relative">
      {hovered && (
        <div className="absolute bg-black text-white px-2 py-1 rounded text-xs pointer-events-none" style={{ left: hovered.x + 8, top: hovered.y + 8 }}>
          {hovered.name}: {hovered.users.toLocaleString()} users
        </div>
      )}
    </div>
  );
}

import { Server } from 'socket.io';
import { UserModel } from '../models/user.model';

export function attachGeoNamespace(io: Server) {
  const ns = io.of('/geo');
  async function compute() {
    const agg = await UserModel.aggregate([{ $match: { lastActiveAt: { $gt: new Date(Date.now() - 60_000) } } }, { $group: { _id: '$countryCode', n: { $sum: 1 } } }]);
    return Object.fromEntries(agg.map(a => [a._id, a.n]));
  }
  ns.on('connection', async (socket) => {
    socket.emit('geo:update', await compute());
  });
  setInterval(async () => { ns.emit('geo:update', await compute()); }, 30_000);
}

