import crypto from 'node:crypto';
import { FlagRuleModel } from '../models/flag-rule.model';

type Rule = { name: string; defaultValue: boolean; rolloutPercent?: number; orgs?: Record<string, boolean>; users?: Record<string, boolean> };

let cache: Map<string, Rule> | null = null;
let cacheAt = 0;
const TTL_MS = 30_000;

async function getRules(): Promise<Map<string, Rule>> {
  if (cache && Date.now() - cacheAt < TTL_MS) return cache;
  const rules = await FlagRuleModel.find({}).lean();
  cache = new Map(rules.map(r => [r.name, r as any as Rule]));
  cacheAt = Date.now();
  return cache;
}

function bucket(seed: string): number {
  const h = crypto.createHash('sha1').update(seed).digest();
  return h.readUInt32BE(0) % 100;
}

export async function isEnabled(name: string, ctx: { userId?: string; orgId?: string }): Promise<boolean> {
  const rules = await getRules();
  const rule = rules.get(name);
  if (!rule) return false;
  if (ctx.userId && rule.users && rule.users[ctx.userId] !== undefined) return rule.users[ctx.userId];
  if (ctx.orgId && rule.orgs && rule.orgs[ctx.orgId] !== undefined) return rule.orgs[ctx.orgId];
  if (rule.rolloutPercent !== undefined && ctx.userId) return bucket(`${ctx.userId}:${name}`) < rule.rolloutPercent;
  return rule.defaultValue;
}

export function invalidateCache() { cache = null; cacheAt = 0; }

import { Request, Response, NextFunction } from 'express';
import { isEnabled } from '../services/flags.service';
import { FlagRuleModel } from '../models/flag-rule.model';

export const myFlags = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const ctx = { userId: req.user?.id, orgId: (req as any).orgId };
    const rules = await FlagRuleModel.find({}).lean();
    const out: Record<string, boolean> = {};
    for (const r of rules) out[r.name] = await isEnabled(r.name, ctx);
    res.json({ flags: out });
  } catch (err) { next(err); }
};

