import { Server, Socket } from 'socket.io';

type MediaState = { muted: boolean; cameraOff: boolean; screenSharing: boolean };
interface AuthedSocket extends Socket { data: { userId: string; displayName: string; roomId?: string; media: MediaState } }

const roomPresence = new Map<string, Map<string, { userId: string; displayName: string; media: MediaState }>>();

export function attachCallNamespace(io: Server) {
  const ns = io.of('/call');
  ns.on('connection', (socket: AuthedSocket) => {
    socket.data.media = { muted: false, cameraOff: false, screenSharing: false };
    socket.on('call:join', (roomId: string) => {
      socket.data.roomId = roomId;
      socket.join(`call:${roomId}`);
      const peers = roomPresence.get(roomId) ?? new Map();
      peers.set(socket.id, { userId: socket.data.userId, displayName: socket.data.displayName, media: socket.data.media });
      roomPresence.set(roomId, peers);
      socket.emit('call:snapshot', Array.from(peers.values()));
      socket.to(`call:${roomId}`).emit('call:peer-joined', { userId: socket.data.userId, displayName: socket.data.displayName, media: socket.data.media });
    });
    socket.on('call:media', (patch: Partial<MediaState>) => {
      if (!socket.data.roomId) return;
      socket.data.media = { ...socket.data.media, ...patch };
      const peers = roomPresence.get(socket.data.roomId);
      const me = peers?.get(socket.id);
      if (me) me.media = socket.data.media;
      ns.to(`call:${socket.data.roomId}`).emit('call:media', { userId: socket.data.userId, media: socket.data.media });
    });
    socket.on('disconnect', () => {
      if (!socket.data.roomId) return;
      const peers = roomPresence.get(socket.data.roomId);
      if (peers) {
        peers.delete(socket.id);
        if (peers.size === 0) roomPresence.delete(socket.data.roomId);
      }
      ns.to(`call:${socket.data.roomId}`).emit('call:peer-left', { userId: socket.data.userId });
    });
  });
}

import { useEffect, useRef, useState } from 'react';
import { io, Socket } from 'socket.io-client';

type MediaState = { muted: boolean; cameraOff: boolean; screenSharing: boolean };
type Peer = { userId: string; displayName: string; media: MediaState };

export function useCallPresence(roomId: string, token: string) {
  const [peers, setPeers] = useState<Peer[]>([]);
  const socketRef = useRef<Socket | null>(null);

  useEffect(() => {
    const socket = io('/call', { auth: { token }, transports: ['websocket'] });
    socketRef.current = socket;
    socket.on('connect', () => socket.emit('call:join', roomId));
    socket.on('call:snapshot', (list: Peer[]) => setPeers(list));
    socket.on('call:peer-joined', (p: Peer) => setPeers(prev => [...prev.filter(x => x.userId !== p.userId), p]));
    socket.on('call:peer-left', ({ userId }: { userId: string }) => setPeers(prev => prev.filter(p => p.userId !== userId)));
    socket.on('call:media', ({ userId, media }: { userId: string; media: MediaState }) => setPeers(prev => prev.map(p => p.userId === userId ? { ...p, media } : p)));
    return () => { socket.removeAllListeners(); socket.disconnect(); };
  }, [roomId, token]);

  const setMedia = (patch: Partial<MediaState>) => socketRef.current?.emit('call:media', patch);
  return { peers, setMedia };
}

import { useCallPresence } from './useCallPresence';

export function CallRoom({ roomId, token }: { roomId: string; token: string }) {
  const { peers, setMedia } = useCallPresence(roomId, token);
  return (
    <div>
      <button onClick={() => setMedia({ muted: !peers.find(p => p.userId === 'me')?.media.muted })}>Toggle mute</button>
      <ul>{peers.map(p => <li key={p.userId}>{p.displayName} - {p.media.muted ? 'muted' : 'unmuted'} - {p.media.cameraOff ? 'camera off' : 'camera on'}</li>)}</ul>
    </div>
  );
}

