export type WidgetConfig = { apiKey: string; orgId?: string; theme?: { primary?: string }; container?: string | HTMLElement };

export class MyChatWidget {
  static VERSION = '1.4.2';
  private root: HTMLElement | null = null;
  private iframe: HTMLIFrameElement | null = null;

  init(config: WidgetConfig) {
    if (this.root) this.destroy();
    const target = typeof config.container === 'string' ? document.querySelector(config.container) as HTMLElement : (config.container ?? document.body);
    this.root = document.createElement('div');
    this.root.id = 'mychat-widget';
    target.appendChild(this.root);
    this.iframe = document.createElement('iframe');
    this.iframe.src = `https://widget.example.com/${MyChatWidget.VERSION}/index.html?apiKey=${encodeURIComponent(config.apiKey)}`;
    this.iframe.style.cssText = 'border:0;width:100%;height:100%;';
    this.root.appendChild(this.iframe);
    window.addEventListener('message', this.onMessage);
  }

  private onMessage = (e: MessageEvent) => {
    if (e.source !== this.iframe?.contentWindow) return;
    // handle host->widget protocol
  };

  destroy() {
    window.removeEventListener('message', this.onMessage);
    this.iframe?.remove();
    this.root?.remove();
    this.root = null; this.iframe = null;
  }
}

export default MyChatWidget;

(function() {
  var script = document.currentScript;
  var version = (script && script.getAttribute('data-version')) || 'latest';
  var apiKey = (script && script.getAttribute('data-api-key'));
  if (!apiKey) { console.error('MyChat: data-api-key required'); return; }
  var pkgUrl = 'https://cdn.example.com/widget/' + version + '/widget.min.js';
  var s = document.createElement('script');
  s.src = pkgUrl;
  s.onload = function() {
    var W = window.MyChatWidget;
    if (!W) { console.error('MyChat: loader did not expose MyChatWidget'); return; }
    var instance = new W();
    instance.init({ apiKey: apiKey });
    // Backward compat: expose old window.MyChat global
    window.MyChat = { init: function(config) { instance.init(config); } };
  };
  document.head.appendChild(s);
})();

