import { Request, Response, NextFunction } from 'express';
import fs from 'node:fs';
import fsPromises from 'node:fs/promises';
import path from 'node:path';
import { FileModel } from '../models/file.model';
import { HttpError } from '../errors/http-error';

const ROOT = path.resolve('/var/uploads');

function resolveSafe(rel: string): string {
  const resolved = path.resolve(ROOT, rel);
  if (!resolved.startsWith(ROOT + path.sep) && resolved !== ROOT) throw new HttpError(400, 'INVALID_PATH');
  return resolved;
}

export const download = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const file = await FileModel.findById(req.params.fileId);
    if (!file) throw new HttpError(404, 'NOT_FOUND');
    const full = resolveSafe(file.relativePath);
    const stat = await fsPromises.stat(full);
    res.setHeader('Content-Type', file.contentType ?? 'application/octet-stream');
    res.setHeader('Accept-Ranges', 'bytes');
    res.setHeader('Cache-Control', 'private, max-age=3600');
    res.setHeader('Content-Disposition', `inline; filename="${encodeURIComponent(file.originalName)}"`);
    const range = req.headers.range;
    if (range) {
      const m = /^bytes=(\d*)-(\d*)$/.exec(range);
      if (!m) { res.status(416).setHeader('Content-Range', `bytes */${stat.size}`); return res.end(); }
      const start = m[1] ? parseInt(m[1], 10) : 0;
      const end = m[2] ? parseInt(m[2], 10) : stat.size - 1;
      if (start >= stat.size || end >= stat.size || start > end) { res.status(416).setHeader('Content-Range', `bytes */${stat.size}`); return res.end(); }
      res.status(206);
      res.setHeader('Content-Range', `bytes ${start}-${end}/${stat.size}`);
      res.setHeader('Content-Length', String(end - start + 1));
      fs.createReadStream(full, { start, end, highWaterMark: 64 * 1024 }).pipe(res);
      return;
    }
    res.setHeader('Content-Length', String(stat.size));
    fs.createReadStream(full, { highWaterMark: 64 * 1024 }).pipe(res);
  } catch (err) { next(err); }
};

